// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.settings = {executionOrder: $input.first().json.settings.executionOrder};
  for (const nodeKey in item.json.nodes) {
    const node = item.json.nodes[nodeKey];
    console.log(node)
    if (node.name === "Sync Settings Form" && node.parameters?.formFields?.values) {
      for (const val of node.parameters.formFields.values) {
        switch(val.fieldLabel) {
          case "Ghost API URL":
            val.defaultValue = $('Sync Settings Form').first().json['Ghost API URL'];
            break;
          case "Webhook URL":
            val.defaultValue = $('Sync Settings Form').first().json['Webhook URL'];
            break;
          case "Ghost Member Added > Added to Mailerlite":
            val.defaultValue = $('Sync Settings Form').first().json['Ghost Member Added > Added to Mailerlite'];
            break;
          case "Ghost Member Removed > Removed from Mailerlite":
            val.defaultValue = $('Sync Settings Form').first().json['Ghost Member Removed > Removed from Mailerlite'];
            break;
        }
      }
    }
  }
}

return $input.all();

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.webhooks = [];
  if ($('Sync Settings Form').first().json['Ghost Member Added > Added to Mailerlite'] === 'Enabled') {
    item.json.webhooks.push({type: 'member.added', action: 'enabled'});
  }
  else {
    item.json.webhooks.push({type: 'member.added', action: 'disabled'});
  }
  if ($('Sync Settings Form').first().json['Ghost Member Removed > Removed from Mailerlite'] === 'Enabled') {
    item.json.webhooks.push({type: 'member.deleted', action: 'enabled'});
  }
  else {
    item.json.webhooks.push({type: 'member.deleted', action: 'disabled'});
  }
}

return $input.all();
